import xml.etree.ElementTree as ET
from xml.dom import minidom
import os
from typing import Optional, Dict, Any, Union
from pathlib import Path


def read_and_validate_xml(
    file_path: Union[str, Path],
    schema_file: Optional[Union[str, Path]] = None,
    encoding: str = 'utf-8',
    max_file_size: int = 10 * 1024 * 1024  # 10 MB default
) -> Dict[str, Any]:
    """
    Reads and validates an XML document uploaded by a user.
    
    Args:
        file_path: Path to the XML file
        schema_file: Optional path to XSD schema file for validation
        encoding: File encoding (default: utf-8)
        max_file_size: Maximum file size in bytes (default: 10MB)
    
    Returns:
        Dictionary containing:
            - 'valid': Boolean indicating if XML is valid
            - 'data': Parsed XML ElementTree root if valid
            - 'errors': List of error messages if invalid
            - 'metadata': Dictionary with file metadata
    """
    result = {
        'valid': False,
        'data': None,
        'errors': [],
        'metadata': {}
    }
    
    # Convert to Path object
    file_path = Path(file_path)
    
    # Check if file exists
    if not file_path.exists():
        result['errors'].append(f"File not found: {file_path}")
        return result
    
    # Check if it's a file
    if not file_path.is_file():
        result['errors'].append(f"Path is not a file: {file_path}")
        return result
    
    # Get file metadata
    file_stats = file_path.stat()
    result['metadata'] = {
        'file_name': file_path.name,
        'file_size': file_stats.st_size,
        'file_path': str(file_path.absolute())
    }
    
    # Check file size
    if file_stats.st_size > max_file_size:
        result['errors'].append(
            f"File size ({file_stats.st_size} bytes) exceeds maximum allowed size ({max_file_size} bytes)"
        )
        return result
    
    # Check if file is empty
    if file_stats.st_size == 0:
        result['errors'].append("File is empty")
        return result
    
    # Try to parse the XML
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        result['data'] = root
        result['metadata']['root_tag'] = root.tag
        result['metadata']['namespaces'] = dict(
            [node for _, node in ET.iterparse(str(file_path), events=['start-ns'])]
        )
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
        return result
    except Exception as e:
        result['errors'].append(f"Error reading file: {str(e)}")
        return result
    
    # Validate well-formedness
    try:
        with open(file_path, 'r', encoding=encoding) as f:
            content = f.read()
            minidom.parseString(content)
    except Exception as e:
        result['errors'].append(f"XML well-formedness validation failed: {str(e)}")
        return result
    
    # XSD Schema validation if schema file is provided
    if schema_file:
        schema_path = Path(schema_file)
        if not schema_path.exists():
            result['errors'].append(f"Schema file not found: {schema_file}")
            return result
        
        try:
            from lxml import etree
            
            # Parse schema
            with open(schema_path, 'rb') as schema_f:
                schema_root = etree.XML(schema_f.read())
                schema = etree.XMLSchema(schema_root)
            
            # Parse and validate XML
            with open(file_path, 'rb') as xml_f:
                xml_doc = etree.parse(xml_f)
                
            if not schema.validate(xml_doc):
                for error in schema.error_log:
                    result['errors'].append(f"Schema validation error: {error.message}")
                return result
                
        except ImportError:
            result['errors'].append(
                "lxml library not available for XSD validation. Install with: pip install lxml"
            )
            return result
        except Exception as e:
            result['errors'].append(f"Schema validation error: {str(e)}")
            return result
    
    # If we got here, the XML is valid
    result['valid'] = True
    return result


def validate_xml_string(
    xml_string: str,
    schema_file: Optional[Union[str, Path]] = None
) -> Dict[str, Any]:
    """
    Validates an XML string.
    
    Args:
        xml_string: XML content as string
        schema_file: Optional path to XSD schema file for validation
    
    Returns:
        Dictionary containing validation results
    """
    result = {
        'valid': False,
        'data': None,
        'errors': [],
        'metadata': {}
    }
    
    # Check if string is empty
    if not xml_string or not xml_string.strip():
        result['errors'].append("XML string is empty")
        return result
    
    # Try to parse the XML string
    try:
        root = ET.fromstring(xml_string)
        result['data'] = root
        result['metadata']['root_tag'] = root.tag
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
        return result
    except Exception as e:
        result['errors'].append(f"Error parsing XML string: {str(e)}")
        return result
    
    # Validate well-formedness
    try:
        minidom.parseString(xml_string)
    except Exception as e:
        result['errors'].append(f"XML well-formedness validation failed: {str(e)}")
        return result
    
    # XSD Schema validation if schema file is provided
    if schema_file:
        schema_path = Path(schema_file)
        if not schema_path.exists():
            result['errors'].append(f"Schema file not found: {schema_file}")
            return result
        
        try:
            from lxml import etree
            
            # Parse schema
            with open(schema_path, 'rb') as schema_f:
                schema_root = etree.XML(schema_f.read())
                schema = etree.XMLSchema(schema_root)
            
            # Parse and validate XML
            xml_doc = etree.fromstring(xml_string.encode('utf-8'))
            
            if not schema.validate(xml_doc):
                for error in schema.error_log:
                    result['errors'].append(f"Schema validation error: {error.message}")
                return result
                
        except ImportError:
            result['errors'].append(
                "lxml library not available for XSD validation. Install with: pip install lxml"
            )
            return result
        except Exception as e:
            result['errors'].append(f"Schema validation error: {str(e)}")
            return result
    
    # If we got here, the XML is valid
    result['valid'] = True
    return result